  1	import {
  2	  Alert,
  3	  Badge,
  4	  Button,
  5	  MenuToggle,
  6	  MenuToggleElement,
  7	  Select,
  8	  SelectList,
  9	  SelectOption,
 10	  SelectOptionProps,
 11	  Spinner,
 12	  TextInputGroup,
 13	  TextInputGroupMain,
 14	  TextInputGroupUtilities,
 15	} from '@patternfly/react-core';
 16	import { TimesIcon } from '@patternfly/react-icons';
 17	import React, { useEffect } from 'react';
 18	import { useTranslation } from 'react-i18next';
 19	import { TestIds } from '../../test-ids';
 20	import { useAttributeValueData } from './attribute-value-data';
 21	import { Attribute, Filters } from './filter.types';
 22	import { isOption } from './filters-from-params';
 23	
 24	interface SearchSelectProps {
 25	  attribute: Attribute;
 26	  onSelect: (selections: Set<string>, expandedSelections?: Map<string, Set<string>>) => void;
 27	  filters: Filters;
 28	  customBadgeTextDependsOnData?: boolean;
 29	  isCheckbox?: boolean;
 30	  tenant?: string;
 31	}
 32	
 33	const ERROR_VALUE = '__attribute_error';
 34	const NO_RESULTS = 'no results';
 35	
 36	const createItemId = (value: string) => `select-multi-typeahead-${value.replace(' ', '-')}`;
 37	
 38	const getOptionComponents = (
 39	  attributeOptions: SelectOptionProps[],
 40	  attributeError: Error | undefined,
 41	  attributeLoading: boolean,
 42	  selections: Array<string>,
 43	  focusedItemIndex: number | null,
 44	  onInputKeyDown: (event: React.KeyboardEvent) => void,
 45	) => {
 46	  if (attributeLoading) {
 47	    return [
 48	      <SelectOption isLoading key="custom-loading" value="loading" hasCheckbox={false}>
 49	        <Spinner size="lg" />
 50	      </SelectOption>,
 51	    ];
 52	  }
 53	
 54	  if (attributeError) {
 55	    return [
 56	      <SelectOption key="error" value={ERROR_VALUE}>
 57	        <Alert
 58	          variant="danger"
 59	          isInline
 60	          isPlain
 61	          title={attributeError.message || String(attributeError)}
 62	        />
 63	      </SelectOption>,
 64	    ];
 65	  }
 66	
 67	  const sortedOptions = attributeOptions.sort((a, b) => {
 68	    const aSelected = selections.includes(a.value);
 69	    const bSelected = selections.includes(b.value);
 70	
 71	    if (aSelected && !bSelected) {
 72	      return -1;
 73	    }
 74	    if (!aSelected && bSelected) {
 75	      return 1;
 76	    }
 77	    if (a.children && b.children) {
 78	      return String(a.children).localeCompare(String(b.children));
 79	    }
 80	    return String(a.value).localeCompare(String(b.value));
 81	  });
 82	
 83	  return sortedOptions.map((attributeOption, index) => (
 84	    <SelectOption
 85	      key={attributeOption.value || attributeOption.children}
 86	      value={attributeOption.value}
 87	      hasCheckbox={attributeOption.hasCheckbox}
 88	      isSelected={selections.includes(attributeOption.value)}
 89	      isFocused={focusedItemIndex === index}
 90	      id={createItemId(attributeOption.value)}
 91	      onKeyDown={onInputKeyDown}
 92	    >
 93	      {attributeOption.children ?? attributeOption.value}
 94	    </SelectOption>
 95	  ));
 96	};
 97	
 98	export const SearchSelect: React.FC<SearchSelectProps> = ({
 99	  attribute,
100	  onSelect,
101	  filters,
102	  isCheckbox = false,
103	  tenant,
104	}) => {
105	  const { t } = useTranslation('plugin__logging-view-plugin');
106	
107	  const { getAttributeOptions, attributeOptions, attributeError, attributeLoading } =
108	    useAttributeValueData(attribute);
109	  const [selections, setSelections] = React.useState<Array<string>>([]);
110	  const [viewableOptions, setViewableOptions] = React.useState<SelectOptionProps[]>([]);
111	
112	  const [isOpen, setIsOpen] = React.useState(false);
113	  const [inputValue, setInputValue] = React.useState<string>('');
114	  const [focusedItemIndex, setFocusedItemIndex] = React.useState<number | null>(null);
115	  const [activeItemId, setActiveItemId] = React.useState<string | null>(null);
116	
117	  const textInputRef = React.useRef<HTMLInputElement>();
118	  const listRef = React.useRef<HTMLDivElement>(null);
119	
120	  const handleClickOutside = (event: MouseEvent) => {
121	    if (isOpen && !listRef.current?.contains(event.target as Node)) {
122	      setIsOpen(false);
123	    }
124	  };
125	
126	  React.useEffect(() => {
127	    if (isOpen) {
128	      window.addEventListener('click', handleClickOutside);
129	    }
130	    return () => {
131	      window.removeEventListener('click', handleClickOutside);
132	    };
133	  }, [isOpen]);
134	
135	  React.useEffect(() => {
136	    let newSelectOptions: SelectOptionProps[] = attributeOptions.map((attributeOption) => {
137	      return { ...attributeOption, hasCheckbox: true };
138	    });
139	    // Filter menu items based on the text input value when one exists
140	    if (inputValue) {
141	      newSelectOptions = newSelectOptions.filter((menuItem) =>
142	        String(menuItem.value).toLowerCase().includes(inputValue.toLowerCase()),
143	      );
144	      // When no options are found after filtering, display 'No results found'
145	      if (!newSelectOptions.length) {
146	        newSelectOptions = [
147	          {
148	            isAriaDisabled: true,
149	            children: `${t('No results found for')} "${inputValue}"`,
150	            value: NO_RESULTS,
151	            hasCheckbox: false,
152	          },
153	        ];
154	      }
155	      // Open the menu when the input value changes and the new value is not empty
156	      if (!isOpen) {
157	        setIsOpen(true);
158	      }
159	    } else {
160	      if (newSelectOptions.length === 0 && isOpen) {
161	        newSelectOptions = [
162	          {
163	            isAriaDisabled: true,
164	            children: t('No options available'),
165	            value: NO_RESULTS,
166	            hasCheckbox: false,
167	          },
168	        ];
169	      }
170	    }
171	    setViewableOptions(newSelectOptions);
172	  }, [inputValue, attributeOptions]);
173	
174	  const setActiveAndFocusedItem = (itemIndex: number) => {
175	    setFocusedItemIndex(itemIndex);
176	    const focusedItem = viewableOptions[itemIndex];
177	    setActiveItemId(createItemId(focusedItem.value));
178	  };
179	
180	  const handleClear = () => {
181	    setInputValue('');
182	    resetActiveAndFocusedItem();
183	    textInputRef?.current?.focus();
184	  };
185	
186	  useEffect(() => {
187	    if (attribute.isItemSelected) {
188	      const selectedItems = attributeOptions.filter((item) =>
189	        attribute.isItemSelected?.(item.value, filters),
190	      );
191	
192	      setSelections(selectedItems.map((item) => item.value));
193	    } else {
194	      setSelections(Array.from(filters[attribute.id] ?? []));
195	    }
196	  }, [filters, attributeOptions]);
197	
198	  const handleSelect = (
199	    _: React.MouseEvent<Element, MouseEvent> | undefined,
200	    value: string | number | undefined,
201	  ) => {
202	    const selectedValue = isOption(value) ? value.value : String(value);
203	
204	    let expandedFilters: Map<string, Set<string>> | undefined = undefined;
205	
206	    if (selectedValue && selectedValue !== ERROR_VALUE) {
207	      if (!isCheckbox) {
208	        expandedFilters = attribute.expandSelection
209	          ? attribute.expandSelection(new Set([selectedValue]))
210	          : undefined;
211	
212	        onSelect(new Set([selectedValue]), expandedFilters);
213	        setIsOpen(false);
214	      } else {
215	        const changedSelections = new Set(selections);
216	        if (changedSelections.has(selectedValue)) {
217	          changedSelections.delete(selectedValue);
218	
219	          expandedFilters = attribute.expandSelection
220	            ? attribute.expandSelection(changedSelections)
221	            : undefined;
222	        } else {
223	          changedSelections.add(selectedValue);
224	
225	          expandedFilters = attribute.expandSelection
226	            ? attribute.expandSelection(changedSelections)
227	            : undefined;
228	        }
229	
230	        onSelect(changedSelections, expandedFilters);
231	      }
232	    }
233	  };
234	
235	  const onToggleClick = () => {
236	    setIsOpen(!isOpen);
237	    textInputRef?.current?.focus();
238	  };
239	
240	  React.useEffect(() => {
241	    getAttributeOptions();
242	  }, [tenant]);
243	
244	  const resetActiveAndFocusedItem = () => {
245	    setFocusedItemIndex(null);
246	    setActiveItemId(null);
247	  };
248	
249	  const closeMenu = () => {
250	    setIsOpen(false);
251	    resetActiveAndFocusedItem();
252	  };
253	
254	  const onInputClick = () => {
255	    if (!isOpen) {
256	      setIsOpen(true);
257	    } else if (!inputValue) {
258	      closeMenu();
259	    }
260	  };
261	
262	  const onInputKeyDown = (event: React.KeyboardEvent) => {
263	    const focusedItem = focusedItemIndex !== null ? viewableOptions[focusedItemIndex] : null;
264	    const keypress = event.key;
265	
266	    if (keypress === 'Enter') {
267	      if (isOpen && focusedItem && focusedItem.value !== NO_RESULTS) {
268	        handleSelect(undefined, focusedItem.value);
269	      } else if (!isOpen) {
270	        setIsOpen(true);
271	      }
272	      return;
273	    }
274	
275	    let indexToFocus = 0;
276	    if (!isOpen) {
277	      setIsOpen(true);
278	    }
279	
280	    if (keypress === 'ArrowUp') {
281	      event.preventDefault();
282	      // When no index is set or at the first index, focus to the last
283	      // otherwise decrement focus index
284	      if (focusedItemIndex === null || focusedItemIndex === 0) {
285	        indexToFocus = viewableOptions.length - 1;
286	      } else {
287	        indexToFocus = focusedItemIndex - 1;
288	      }
289	      setActiveAndFocusedItem(indexToFocus);
290	    } else if (keypress === 'ArrowDown') {
291	      event.preventDefault();
292	      // When no index is set or at the last index, focus to the first,
293	      // otherwise increment focus index
294	      if (focusedItemIndex === null || focusedItemIndex === viewableOptions.length - 1) {
295	        indexToFocus = 0;
296	      } else {
297	        indexToFocus = focusedItemIndex + 1;
298	      }
299	      setActiveAndFocusedItem(indexToFocus);
300	    }
301	  };
302	
303	  const onTextInputChange = (_event: React.FormEvent<HTMLInputElement>, value: string) => {
304	    setInputValue(value);
305	    resetActiveAndFocusedItem();
306	  };
307	
308	  const titleId = `attribute-value-selector-${attribute.id}`;
309	
310	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
311	    <MenuToggle
312	      variant="typeahead"
313	      ref={toggleRef}
314	      onClick={onToggleClick}
315	      isExpanded={isOpen}
316	      data-test={TestIds.AttributeOptions}
317	      style={
318	        {
319	          width: '230px',
320	          alignItems: 'center',
321	        } as React.CSSProperties
322	      }
323	      key={`attribute-toggle-${attribute.id}`}
324	      className="lv-plugin__typeahead-toggle"
325	      badge={!attributeLoading && <Badge isRead>{selections.length}</Badge>}
326	    >
327	      <TextInputGroup isPlain>
328	        <TextInputGroupMain
329	          value={inputValue}
330	          onClick={onInputClick}
331	          onChange={onTextInputChange}
332	          onKeyDown={onInputKeyDown}
333	          id="attribute-typeahead-multiselect"
334	          autoComplete="off"
335	          innerRef={textInputRef}
336	          placeholder={t('Filter by {{attributeName}}', {
337	            attributeName: attribute.name,
338	          })}
339	          {...(activeItemId && { 'aria-activedescendant': activeItemId })}
340	          role="combobox"
341	          isExpanded={isOpen}
342	          aria-controls="select-multi-typeahead-checkbox-listbox"
343	        />
344	        {inputValue.length > 0 && (
345	          <TextInputGroupUtilities>
346	            <Button variant="plain" onClick={handleClear} aria-label="Clear input value">
347	              <TimesIcon aria-hidden />
348	            </Button>
349	          </TextInputGroupUtilities>
350	        )}
351	      </TextInputGroup>
352	    </MenuToggle>
353	  );
354	
355	  return (
356	    <div ref={listRef}>
357	      <span id={titleId} hidden>
358	        {attribute.name}
359	      </span>
360	      <Select
361	        onSelect={handleSelect}
362	        isOpen={isOpen}
363	        placeholder={t('Filter by {{attributeName}}', {
364	          attributeName: attribute.name,
365	        })}
366	        aria-labelledby={titleId}
367	        aria-placeholder={t('Search')}
368	        className="lv-plugin__search-select"
369	        toggle={toggle}
370	        maxMenuHeight="300px"
371	      >
372	        <SelectList
373	          isAriaMultiselectable
374	          key={`select-list-${attribute.id}-${viewableOptions.length}`}
375	        >
376	          {getOptionComponents(
377	            viewableOptions,
378	            attributeError,
379	            attributeLoading,
380	            selections,
381	            focusedItemIndex,
382	            onInputKeyDown,
383	          )}
384	        </SelectList>
385	      </Select>
386	    </div>
387	  );
388	};

